class MinStack {
    stack<int> st, mn;
public:
    MinStack() {}
    void push(int val) {
        st.push(val);
        mn.push(mn.empty() ? val : min(mn.top(), val));
    }
    void pop() { st.pop(); mn.pop(); }
    int top() { return st.top(); }
    int getMin() { return mn.top(); }
};

